<div class="w-full min-w-0 border-[1.5px] border-[var(--pg-bdr)] rounded-[10px] bg-[var(--pg-bg)] px-3 max-sm:px-2.5 py-[7px] flex flex-col gap-[6px]">
    <span class="text-[9.5px] font-bold text-[var(--pg-lbl)] uppercase tracking-[0.06em]">Pages</span>
    <div class="flex items-center gap-[7px] min-w-0">
        <button type="button" data-page-minus class="w-[25px] h-[25px] shrink-0 flex items-center justify-center rounded-[6px] border-[1.5px] border-[var(--pg-btn-bdr)] bg-[var(--pg-btn-bg)] text-[var(--pg-btn-clr)] text-[15px] font-bold cursor-pointer outline-none transition-all duration-150 hover:!bg-[#f16700] hover:!border-[#f16700] hover:!text-white">-</button>
        <span class="text-[14px] font-extrabold text-[var(--pg-num)] min-w-[18px] text-center" data-pages-value>1</span>
        <button type="button" data-page-plus class="w-[25px] h-[25px] shrink-0 flex items-center justify-center rounded-[6px] border-[1.5px] border-[var(--pg-btn-bdr)] bg-[var(--pg-btn-bg)] text-[var(--pg-btn-clr)] text-[15px] font-bold cursor-pointer outline-none transition-all duration-150 hover:!bg-[#f16700] hover:!border-[#f16700] hover:!text-white">+</button>
        <span class="text-[11.5px] font-medium text-[var(--pg-wrd)] truncate" data-words-value>250 words</span>
    </div>
</div>
